export function urlsToXml(
  urls: ResolvedSitemapUrl[],
  resolvers: NitroUrlResolvers,
  { version, xsl, credits, minify }: Pick<ModuleRuntimeConfig, 'version' | 'xsl' | 'credits' | 'minify'>,
  errorInfo?: { messages: string[], urls: string[] },
): string {
  let xslHref = xsl ? resolvers.relativeBaseUrlResolver(xsl) : false

  if (xslHref && errorInfo?.messages.length) {
    xslHref = withQuery(xslHref, {
      errors: 'true',
      error_messages: errorInfo.messages,
      error_urls: errorInfo.urls,
    })
  }

  const NL = minify ? '' : '\n'
  const I1 = minify ? '' : '    '
  const I2 = minify ? '' : '        '
  const I3 = minify ? '' : '            '
  const I4 = minify ? '' : '                '

  let xml = xslHref
    ? `<?xml version="1.0" encoding="UTF-8"?><?xml-stylesheet type="text/xsl" href="${escapeValueForXml(xslHref)}"?>${NL}`
    : `<?xml version="1.0" encoding="UTF-8"?>${NL}`

  xml += URLSET_OPENING_TAG + NL

  for (const url of urls) {
    xml += buildUrlXml(url, NL, I1, I2, I3, I4) + NL
  }

  xml += '</urlset>'

  if (credits) {
    xml += `${NL}<!-- XML Sitemap generated by @nuxtjs/sitemap v${version} at ${new Date().toISOString()} -->`
  }

  return xml
}

export function normaliseDate(d: Date | string) {
  // lastmod must adhere to W3C Datetime encoding rules
  if (typeof d === 'string') {
    // correct a time component without a timezone
    const tIdx = d.indexOf('T')
    if (tIdx !== -1) {
      const t = d.slice(tIdx + 1)
      if (!t.includes('+') && !t.includes('-') && !t.includes('Z')) {
        // add UTC timezone
        d += 'Z'
      }
    }
    // skip invalid w3c date
    if (!isValidW3CDate(d))
      return false
    // otherwise we need to parse it
    d = new Date(d)
    d.setMilliseconds(0)
    // check for invalid date
    if (Number.isNaN(d.getTime()))
      return false
  }
  const z = (n: number) => (`0${n}`).slice(-2)
  // need to normalise for google sitemap spec
  const date = `${d.getUTCFullYear()
  }-${
    z(d.getUTCMonth() + 1)
  }-${
    z(d.getUTCDate())
  }`
  // check if we have a time set
  if (d.getUTCHours() > 0 || d.getUTCMinutes() > 0 || d.getUTCSeconds() > 0) {
    return (
      `${date}T${
        z(d.getUTCHours())
      }:${
        z(d.getUTCMinutes())
      }:${
        z(d.getUTCSeconds())
      }Z`
    )
  }
  return date
}

() => {
  const nuxt = useNuxtApp()
  const baseURL = useStrapiUrl()
  const version = useStrapiVersion()
  const token = useStrapiToken()

  return async <T> (url: string, fetchOptions: FetchOptions = {}): Promise<T> => {
    const headers: HeadersInit = {}

    if (token && token.value) {
      headers.Authorization = `Bearer ${token.value}`
    }

    // Map params according to strapi v3 and v4 formats
    if (fetchOptions.params) {
      const params = stringify(fetchOptions.params as Record<string, unknown>)
      if (params) {
        url = `${url}?${params}`
      }
      fetchOptions = { ...fetchOptions }
      delete fetchOptions.params
    }

    try {
      // @ts-expect-error method is not explicitly typed
      return await $fetch<T>(url, {
        retry: 0,
        baseURL,
        ...fetchOptions,
        headers: {
          ...headers,
          ...fetchOptions.headers
        }
      })
    } catch (err) {
      const e: Strapi3Error | Strapi4Error | Strapi5Error = err.data || defaultErrors(err)[version]

      nuxt.hooks.callHook('strapi:error', e)
      throw e
    }
  }
}

export function base64Encode(data: ArrayBuffer | Uint8Array | string): string {
  const buff = validateBinaryLike(data);
  if (globalThis.Buffer) {
    return globalThis.Buffer.from(buff).toString("base64url");
  }
  // Credits: https://gist.github.com/enepomnyaschih/72c423f727d395eeaa09697058238727
  const bytes: number[] = [];
  let i;
  const len = buff.length;
  for (i = 2; i < len; i += 3) {
    bytes.push(
      base64Code[buff[i - 2]! >> 2],
      base64Code[((buff[i - 2]! & 0x03) << 4) | (buff[i - 1]! >> 4)],
      base64Code[((buff[i - 1]! & 0x0f) << 2) | (buff[i]! >> 6)],
      base64Code[buff[i]! & 0x3f],
    );
  }
  if (i === len + 1) {
    // 1 octet yet to write
    bytes.push(base64Code[buff[i - 2]! >> 2], base64Code[(buff[i - 2]! & 0x03) << 4]);
  }
  if (i === len) {
    // 2 octets yet to write
    bytes.push(
      base64Code[buff[i - 2]! >> 2],
      base64Code[((buff[i - 2]! & 0x03) << 4) | (buff[i - 1]! >> 4)],
      base64Code[(buff[i - 1]! & 0x0f) << 2],
    );
  }

  return String.fromCharCode(...bytes);
}
